{
  "analysis": "We have inspected the cost model and inputs. Baseline plans are poor. The correct evaluation method is `CostModel.plan_metrics`; the previous full-metric print was truncated because it included the huge `latencies` list. We need to generate optimized plans that group by aligned prompt shape and split by generation length to reduce decode padding/cost, while enforcing at most 8 unique shapes across both buckets. No optimized plan has been verified yet.",
  "plan": "Create an optimizer/evaluator script that:
1. Loads both request files.
2. Selects a global set of up to 8 `seq_align` representatives, allocating more to bucket 1's wider prompt distribution.
3. Assigns requests to the smallest representative >= their aligned prompt length.
4. Within each shape group, sorts by `gen_len` and splits into batches with small `G_max` and batch sizes.
5. Writes both plan files.
6. Evaluates with `plan_metrics`, printing only scalar metrics and threshold pass/fail.",
  "commands": [
    {
      "keystrokes": "cat > /app/task_file/scripts/optimizer.py <<'PY'
#!/usr/bin/env python3
import json, os, math, collections
sys_path = '/app/task_file/scripts'
import sys
sys.path.insert(1, sys_path)
from cost_model import CostModel, align, HEADS, HIDDEN

GRAN = 64
MAX_SHAPES = 8
THRESH = {
    'plan_b1.jsonl': dict(cost=3.0e11, pad_ratio=0.055, p95_latency_ms=2.1e6, sequential_timecost=2.7e8),
    'plan_b2.jsonl': dict(cost=4.8e10, pad_ratio=0.15, p95_latency_ms=2.1e5, sequential_timecost=3.2e7),
}

def load(path):
    return [json.loads(l) for l in open(path)]

def uniq_sorted(reqs):
    seen = set()
    out = []
    for r in reqs:
        s = align(r['prompt_len'], GRAN)
        if s not in seen:
            seen.add(s)
            out.append(s)
    return sorted(out)

def choose_reps(u1, u2, k1, k2):
    reps = []
    for u, k in ((u1, k1), (u2, k2)):
        if not u:
            continue
        if len(u) <= k:
            reps.extend(u)
        else:
            step = len(u) / k
            chosen = set()
            for i in range(k):
                idx = min(len(u)-1, int(round((i + 1) * step)) - 1)
                chosen.add(u[idx])
            chosen.add(u[-1])
            reps.extend(sorted(chosen))
    reps = sorted(set(reps))
    return reps[:MAX_SHAPES] if len(reps) > MAX_SHAPES else reps

def assign_rep(s, reps):
    for r in reps:
        if r >= s:
            return r
    return reps[-1]

def build_plan(reqs, reps, batch_max_g=None, batch_max_size=None):
    groups = collections.defaultdict(list)
    for r in reqs:
        s = align(r['prompt_len'], GRAN)
        rep = assign_rep(s, reps)
        groups[rep].append(r)
    recs = []
    bid = 0
    for rep in sorted(groups):
        grp = sorted(groups[rep], key=lambda x: x['gen_len'])
        batches = []
        cur = []
        cur_max = 1
        for r in grp:
            g = r['gen_len']
            if cur and ((batch_max_g and max(cur_max, g) > batch_max_g) or (batch_max_size and len(cur) >= batch_max_size)):
                batches.append(cur)
                cur = [r]
                cur_max = g
            else:
                cur.append(r)
                cur_max = max(cur_max, g)
        if cur:
            batches.append(cur)
        for b in batches:
            bid += 1
            batch_id = f"b-{bid:04d}"
            for r in b:
                recs.append({
                    'request_id': r['request_id'],
                    'batch_id': batch_id,
                    'shape': {'seq_align': rep, 'heads_align': HEADS, 'hidden_align': HIDDEN}
                })
    return recs

def write(path, recs):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w') as f:
        for r in recs:
            f.write(json.dumps(r) + '\n')

def metrics_for(plan_path, req_path):
    reqs = {r['request_id']: r for r in load(req_path)}
    plan = load(plan_path)
    return CostModel(granularity=GRAN).plan_metrics(reqs, plan)

def validate(plan_path, req_path):
    reqs = {r['request_id']: r for r in load(req_path)}
    plan = load(plan_path)
    ids = [p['request_id'] for p in plan]
    shapes = collections.Counter(
        (p['shape']['seq_align'], p['shape']['heads_align'], p['shape']['hidden_align'])
        for p in plan
    )
    return {
        'all_included': len(ids) == len(reqs) == len(set(ids)),
        'shapes_ok': len(shapes) <= MAX_SHAPES and all(s[1] == 32 and s[2] == 4096 for s in shapes),
        'seq_ok': all(align(reqs[p['request_id']]['prompt_len'], GRAN) <= p['shape']['seq_align'] and p['shape']['seq_align'] % GRAN == 0 for p in plan)
    }

def main():
    root = '/app/task_file'
    in1 = f'{root}/input_data/requests_bucket_1.jsonl'
    in2 = f'{root}/input_data/requests_bucket_2.jsonl'
    out1 = f'{root}/output_data/plan_b1.jsonl'
    out2 = f'{root}/output_data/plan_b2.jsonl'
    reqs1 = load(in1)
    reqs2 = load(in2)
    u1 = uniq_sorted(reqs1)
    u2 = uniq_sorted(reqs2)

    best = None
    for k1 in range(1, 8):
        k2 = MAX_SHAPES - k1
        reps = choose_reps(u1, u2, k1, k2)
        if len(reps) > MAX_SHAPES:
            continue
        for g1 in [32, 48, 64, 96, 128, 192, 256, 384, 512, 768, 1024]:
            for s1 in [16, 24, 32, 48, 64, 96, 128, 192, 256, 400, 800]:
                for g2 in [16, 24, 32, 48, 64, 96, 128, 192, 256, 384, 512]:
                    for s2 in [16, 24, 32, 48, 64, 96, 128, 192, 256, 400]:
                        p1 = build_plan(reqs1, reps, g1, s1)
                        p2 = build_plan(reqs2, reps, g2, s2)
                        shapes = set()
                        for p in p1 + p2:
                            sh = p['shape']
                            shapes.add((sh['seq_align'], sh['heads_align'], sh['hidden_align']))
                        if len(shapes) > MAX_SHAPES:
                            continue
                        write(out1, p1)
                        write(out2, p2)
                        m1 = metrics_for(out1, in1)
                        m2 = metrics_for(out2, in2)
                        if (m1['cost'] <= THRESH['plan_b1.jsonl']['cost'] and m1['pad_ratio'] <= THRESH['plan_b1.jsonl']['pad_ratio']
                            and m1['p95_latency_ms'] <= THRESH['plan_b1.jsonl']['p95_latency_ms'] and m1['sequential_timecost'] <= THRESH['plan_b1.jsonl']['sequential_timecost']
                            and m2['cost'] <= THRESH['plan_b2.jsonl']['cost'] and m2['pad_ratio'] <= THRESH['plan_b2.jsonl']['pad_ratio']
                            and m2['p95_latency_ms'] <= THRESH['plan_b2.jsonl']['p95_latency_ms'] and m2['sequential_timecost'] <= THRESH['plan_b2.jsonl']['sequential_timecost']):
                            score = m1['cost'] + m2['cost']
                            if best is None or score < best[0]:
                                best = (score, reps, g1, s1, g2, s2, dict(m1), dict(m2))
    if best:
        score, reps, g1, s1, g2, s2, m1, m2 = best
        p1 = build_plan(reqs1, reps, g1, s1)
        p2 = build_plan(reqs2, reps, g2, s2)
        write(out1, p1)
        write(out2, p2)
        print('FOUND PASSING PLAN')
        print('reps', reps, 'g1', g1, 's1', s1, 'g2', g2, 's2', s2)
        print('b1', {k: m1[k] for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']})
        print('b2', {k: m2[k] for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']})
    else:
        print('NO PASSING COMBINATION FOUND IN SEARCHED GRID')
        # write a reasonable default to inspect
        reps = choose_reps(u1, u2, 5, 3)
        p1 = build_plan(reqs1, reps, 128, 64)
        p2 = build_plan(reqs2, reps, 64, 64)
        write(out1, p1)
        write(out2, p2)
    for name, out, inp in [('plan_b1.jsonl', out1, in1), ('plan_b2.jsonl', out2, in2)]:
        m = metrics_for(out, inp)
        v = validate(out, inp)
        th = THRESH[name]
        print(name)
        print('  valid', v)
        print('  cost=%.6g pad_ratio=%.6f p95=%.6g seqtime=%.6g' % (m['cost'], m['pad_ratio'], m['p95_latency_ms'], m['sequential_timecost']))
        print('  pass', all(m[k] <= th[k] for k in th))

if __name__ == '__main__':
    main()
